// /frontend/src/components/Forecast.jsx
import React from "react";

// OpenWeather daily entries: { dt, temp:{min,max}, weather:[{description,icon}] }
function DayRow({ d, i }) {
  const dt = d?.dt ? new Date(d.dt * 1000) : new Date(Date.now() + (i + 1) * 86400_000);
  const wday = dt.toLocaleDateString([], { weekday: "short" });
  const hi = Math.round(d?.temp?.max ?? 0);
  const lo = Math.round(d?.temp?.min ?? 0);
  const desc = d?.weather?.[0]?.description ?? "";
  // const icon = d?.weather?.[0]?.icon ?? "02d";
  // const iconUrl = `https://openweathermap.org/img/wn/${icon}.png`;

  return (
    <div className="flex items-center justify-between px-4 py-3 rounded-xl bg-white/5">
      <div className="w-16 opacity-80">{wday}</div>
      <div className="flex items-center gap-2 flex-1 min-w-0">
        {/* <img src={iconUrl} alt="" className="h-6 w-6 shrink-0" /> */}
        <div className="truncate capitalize opacity-80">{desc}</div>
      </div>
      <div className="w-24 text-right">
        <span className="opacity-80">{hi}°</span>
        <span className="opacity-60 ml-2">{lo}°</span>
      </div>
    </div>
  );
}

export default function Forecast({ daily = [] }) {
  const days = Array.isArray(daily) ? daily : [];
  if (!days.length) {
    return (
      <div className="rounded-2xl backdrop-blur-xl bg-black/40 ring-1 ring-white/10 p-4 text-sm opacity-70">
        No forecast data yet.
      </div>
    );
  }

  return (
    <div className="rounded-2xl backdrop-blur-xl bg-black/40 ring-1 ring-white/10 p-3">
      {/* Mobile: horizontal swipe */}
      <div className="md:hidden flex gap-3 overflow-x-auto snap-x snap-mandatory">
        {days.map((d, i) => (
          <div key={i} className="min-w-[80%] snap-start">
            <DayRow d={d} i={i} />
          </div>
        ))}
      </div>

      {/* Desktop: 2-col grid */}
      <div className="hidden md:grid md:grid-cols-2 md:gap-3">
        {days.map((d, i) => (
          <DayRow key={i} d={d} i={i} />
        ))}
      </div>
    </div>
  );
}
